import React, { useEffect, useState } from "react";
import axios from "axios";

const AdminDashboard = () => {
  const [stats, setStats] = useState(null);
  const [error, setError] = useState("");
  const apiURL = process.env.REACT_APP_API_URL || "http://localhost:8000";

  useEffect(() => {
    const fetchStats = async () => {
      setError("");
      try {
        const raw = localStorage.getItem("adminJwt");
        if (!raw) {
          setError("Missing admin token");
          return;
        }
        const { token } = JSON.parse(raw);
        const res = await axios.get(`${apiURL}/api/admin/dashboard`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (res.data && res.data.success) {
          setStats(res.data.data);
        } else {
          setError(res.data.error || "Failed to load admin dashboard");
        }
      } catch (err) {
        setError("Unauthorized or network error");
      }
    };
    fetchStats();
  }, [apiURL]);

  if (error) {
    return (
      <div className="max-w-2xl mx-auto mt-10 p-4 border rounded">
        <p className="text-red-600">{error}</p>
      </div>
    );
  }

  if (!stats) {
    return (
      <div className="max-w-2xl mx-auto mt-10 p-4 border rounded">
        <p>Loading admin dashboard...</p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto mt-10 p-6 border rounded">
      <h2 className="text-2xl font-semibold mb-4">Admin Dashboard</h2>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="p-4 border rounded">
          <p className="text-gray-600">Users</p>
          <p className="text-2xl font-bold">{stats.users}</p>
        </div>
        <div className="p-4 border rounded">
          <p className="text-gray-600">Products</p>
          <p className="text-2xl font-bold">{stats.products}</p>
        </div>
        <div className="p-4 border rounded">
          <p className="text-gray-600">Orders</p>
          <p className="text-2xl font-bold">{stats.orders}</p>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
